def _face_win_cap(model, d, f):
    return sum(model.comp[d, f, fp] for fp in model.f) <= len(model.f) - 1
model.face_win_cap = Constraint(model.d, model.f, rule=_face_win_cap)

def _d2_dominates(model, f):
    return model.fval['dice2', f] >= model.fval['dice1', f]
model.d2_dominates = Constraint(model.f, rule=_d2_dominates)

def _lowface_cap(model, d):
    return sum(model.comp[d, f, 'face1'] for f in model.f) <= len(model.f) - 2
model.lowface_cap = Constraint(model.d, rule=_lowface_cap)

def _couple(model, f):
    return model.fval['dice2', f] >= model.fval['dice1', f]
model.couple = Constraint(model.f, rule=_couple)
def _tighten(model, d, f):
    return sum(model.comp[d, f, fp] for fp in model.f) <= len(model.f) - 2
model.tighten = Constraint(model.d, model.f, rule=_tighten)
